class Transaction:
    def __init__(self, data):
        self._data = data
        self._savepoints = []
        self._active = False

    def begin(self):
        self._savepoints.append(dict(self._data))  # Bug A: shallow copy
        self._active = True

    def commit(self):
        if not self._savepoints:
            raise RuntimeError("No active transaction")
        self._savepoints.pop()
        if not self._savepoints:
            self._active = False

    def rollback(self):
        if not self._savepoints:
            raise RuntimeError("No active transaction")
        saved = self._savepoints.pop()
        self._data = saved  # Bug B: loses external reference
        if not self._savepoints:
            self._active = False

    @property
    def data(self):
        return self._data

    @property
    def active(self):
        return self._active

